      const first = hits.find((h) => typeof h.object.userData.bimPickId === 'string');
      const id = first?.object.userData.bimPickId as string | undefined;
      const store = useBimStore.getState();
      if (additive) {
        if (id) store.toggleSelectedId(id);
        return;
      }
      store.select(id);
    }

